import Foundation
import GRDB

/// Minimal reproduction of the pattern that causes GRDB's SchedulingWatchdog crash.
///
/// The crash occurs when synchronous GRDB DatabasePool operations (like `migrator.migrate`)
/// are called from a Swift async context. GRDB uses `DispatchQueue.getSpecific` to verify
/// it's running on its internal serial queue, but Swift's cooperative thread pool doesn't
/// carry GCD queue-specific values, so the precondition fails with EXC_BREAKPOINT.
public struct DatabaseSetup {
    public let dbPool: DatabasePool

    /// Synchronous setup -- calling this from an async context triggers the crash.
    public func migrate() throws {
        var migrator = DatabaseMigrator()
        migrator.registerMigration("v1") { db in
            try db.create(table: "items") { t in
                t.autoIncrementedPrimaryKey("id")
                t.column("name", .text).notNull()
            }
        }
        try migrator.migrate(dbPool)
    }

    /// Async-safe setup -- uses GRDB's async migration API which properly
    /// dispatches onto the pool's internal queue.
    public func migrateAsync() async throws {
        var migrator = DatabaseMigrator()
        migrator.registerMigration("v1") { db in
            try db.create(table: "items") { t in
                t.autoIncrementedPrimaryKey("id")
                t.column("name", .text).notNull()
            }
        }
        try await migrator.migrate(dbPool)
    }

    public static func live() throws -> DatabaseSetup {
        let dbPool = try DatabasePool(path: ":memory:")
        return DatabaseSetup(dbPool: dbPool)
    }
}

