import Foundation
import GRDB

/// Minimal reproduction of the GRDB SchedulingWatchdog crash.
///
/// The crash occurs when a `Database` handle is used outside of GRDB's
/// designated dispatch queue. GRDB sets a queue-specific key on its internal
/// serial queues and checks it via `DispatchQueue.getSpecific` in
/// `preconditionValidQueue`. When the caller is on the wrong queue (e.g.,
/// Swift's cooperative thread pool), the check fails with EXC_BREAKPOINT.
public struct DatabaseSetup: Sendable {
    public let dbQueue: DatabaseQueue

    /// Performs migration by calling synchronous GRDB methods.
    /// Safe when called from a regular dispatch queue or synchronous context.
    public func migrate() throws {
        var migrator = DatabaseMigrator()
        migrator.registerMigration("v1") { db in
            try db.create(table: "items") { t in
                t.autoIncrementedPrimaryKey("id")
                t.column("name", .text).notNull()
            }
        }
        try migrator.migrate(dbQueue)
    }

    /// Inserts a row using the synchronous write API.
    public func insertItem(name: String) throws {
        try dbQueue.write { db in
            try db.execute(sql: "INSERT INTO items (name) VALUES (?)", arguments: [name])
        }
    }

    /// Reads all items using the synchronous read API.
    public func fetchAllItemNames() throws -> [String] {
        try dbQueue.read { db in
            try String.fetchAll(db, sql: "SELECT name FROM items")
        }
    }

    /// Captures a `Database` handle and uses it outside the GRDB closure.
    /// This is the pattern that triggers the SchedulingWatchdog crash.
    @Sendable public func capturedDatabaseHandle() throws -> Database {
        var captured: Database!
        try dbQueue.read { db in
            captured = db
        }
        return captured
    }

    public static func live() throws -> DatabaseSetup {
        let dbQueue = try DatabaseQueue(path: ":memory:")
        return DatabaseSetup(dbQueue: dbQueue)
    }
}

