import Testing
import GRDB
@testable import GRDBCrashRepro

/// Reproduces the GRDB SchedulingWatchdog crash.
///
/// GRDB protects its `Database` handles with queue-specific keys set via
/// `DispatchQueue.setSpecific`. The `preconditionValidQueue` check uses
/// `DispatchQueue.getSpecific` to verify the caller is on GRDB's internal
/// serial queue. Using a `Database` handle outside that queue (e.g. after
/// capturing it from a `read`/`write` closure) triggers EXC_BREAKPOINT.
struct CrashReproTests {

    /// This test captures a `Database` handle from inside a GRDB closure
    /// and then uses it outside, on whatever thread the test runner provides.
    /// This triggers GRDB's SchedulingWatchdog precondition failure.
    ///
    /// Expected: crashes with "Database was not used on the correct thread."
    @Test
    func crash_captured_database_handle() async throws {
        let setup = try DatabaseSetup.live()
        try setup.migrate()

        // Capture the Database handle from inside a read closure
        let db = try setup.capturedDatabaseHandle()

        // Using the captured handle outside GRDB's queue triggers the crash.
        // GRDB checks DispatchQueue.getSpecific which returns nil here
        // (we're on the cooperative thread pool, not GRDB's serial queue).
        _ = try String.fetchAll(db, sql: "SELECT name FROM items")
    }

    /// Fix: always access the database through GRDB's closure-based APIs
    /// which ensure the code runs on the correct internal queue.
    @Test
    func fix_use_closure_api() async throws {
        let setup = try DatabaseSetup.live()
        try setup.migrate()
        try setup.insertItem(name: "test")
        let names = try setup.fetchAllItemNames()
        #expect(names == ["test"])
    }
}

